                                  onClick={() => setViewMode('grid')} 
                                  className={`p-1.5 rounded-sm transition-all ${viewMode === 'grid' ? 'bg-gray-100 text-nexus-royal font-bold' : 'text-gray-400 hover:text-gray-600'}`}
