                  <div className="flex gap-4">
                    <div className="flex items-center gap-2 text-xs text-gray-500 bg-gray-50 px-3 py-1.5 rounded border border-gray-200">
                        <Check className="w-3 h-3 text-green-500" /> Google Maps
