             </div>
          </div>
      )}

      <SelectListModal 
           isOpen={isSelectListModalOpen}
           onClose={() => setIsSelectListModalOpen(false)}
           onConfirm={confirmSaveLeadToList}
           savedLists={savedLists}
           lang={currentLang}
      />

    </div>
  );
};

