import React, { useState } from 'react';
import { Pipeline, Deal } from '../types';
import { Plus, MoreHorizontal, DollarSign, Calendar, AlertCircle } from 'lucide-react';
import { formatCurrency } from '../utils/estimation';

interface PipelineBoardProps {
  pipeline: Pipeline;
  deals: Deal[];
  onDealMove: (dealId: string, newStageId: string) => void;
  onDealClick: (deal: Deal) => void;
  onAddDeal: (stageId: string) => void;
}

const PipelineBoard: React.FC<PipelineBoardProps> = ({ 
  pipeline, 
  deals, 
  onDealMove,
  onDealClick,
  onAddDeal
}) => {
  const [draggedDealId, setDraggedDealId] = useState<string | null>(null);
  const [dragOverStageId, setDragOverStageId] = useState<string | null>(null);

  const handleDragStart = (e: React.DragEvent, dealId: string) => {
    setDraggedDealId(dealId);
    e.dataTransfer.effectAllowed = 'move';
    // Transparent ghost image or custom logic could go here
  };

  const handleDragOver = (e: React.DragEvent, stageId: string) => {
    e.preventDefault(); // Necessary to allow dropping
    if (dragOverStageId !== stageId) {
        setDragOverStageId(stageId);
    }
  };

  const handleDragLeave = () => {
    setDragOverStageId(null);
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    setDragOverStageId(null);
    if (draggedDealId) {
      onDealMove(draggedDealId, stageId);
      setDraggedDealId(null);
    }
  };

  // Calculate totals per stage
  const getStageSummary = (stageId: string) => {
      const stageDeals = deals.filter(d => d.stageId === stageId && d.pipelineId === pipeline.id);
      const totalValue = stageDeals.reduce((sum, d) => sum + (d.value || 0), 0);
      return { count: stageDeals.length, value: totalValue };
  };

  return (
    <div className="h-full overflow-x-auto overflow-y-hidden pb-4">
      <div className="flex h-full gap-4 min-w-max px-1">
        {pipeline.stages.map((stage) => {
          const stageDeals = deals.filter(deal => deal.stageId === stage.id && deal.pipelineId === pipeline.id);
          const summary = getStageSummary(stage.id);
          const isOver = dragOverStageId === stage.id;

          return (
            <div 
              key={stage.id}
              className={`flex flex-col w-80 max-w-xs rounded-xl transition-colors duration-200 ${isOver ? 'bg-blue-50/80 ring-2 ring-nexus-royal/20' : 'bg-gray-100/50'}`}
              onDragOver={(e) => handleDragOver(e, stage.id)}
              onDragLeave={handleDragLeave}
              onDrop={(e) => handleDrop(e, stage.id)}
            >
              {/* Column Header */}
              <div className="p-3 border-b border-gray-200/50 shrink-0 bg-white/40 rounded-t-xl backdrop-blur-sm">
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                     <span className="font-bold text-sm text-nexus-dark uppercase tracking-tight">{stage.name}</span>
                     <span className="bg-gray-200 text-gray-600 px-1.5 py-0.5 rounded text-[10px] font-bold">{summary.count}</span>
                  </div>
                  <MoreHorizontal className="w-4 h-4 text-gray-400 cursor-pointer hover:text-nexus-dark" />
                </div>
                <div className="h-1 w-full rounded-full bg-gray-200 overflow-hidden mb-2">
                    <div className="h-full rounded-full" style={{ width: '100%', backgroundColor: stage.color }}></div>
                </div>
                <div className="text-xs text-gray-500 font-medium">
                   {formatCurrency(summary.value)}
                </div>
              </div>

              {/* Deals Container */}
              <div className="flex-1 overflow-y-auto p-2 space-y-2 custom-scrollbar">
                {stageDeals.map((deal) => (
                  <div
                    key={deal.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, deal.id)}
                    onClick={() => onDealClick(deal)}
                    className={`bg-white p-3 rounded-lg border shadow-sm cursor-grab active:cursor-grabbing hover:shadow-md transition-all group relative border-l-4 ${draggedDealId === deal.id ? 'opacity-50 rotate-3 scale-95' : 'opacity-100'}`}
                    style={{ borderLeftColor: stage.color }}
                  >
                    <div className="flex justify-between items-start mb-2">
                        <span className="text-sm font-bold text-gray-800 line-clamp-2 leading-tight">
                            {deal.companyName}
                        </span>
                    </div>

                    <div className="flex items-center justify-between mt-3">
                        <span className="text-xs font-bold text-gray-600 bg-gray-50 px-2 py-1 rounded border border-gray-100">
                           {formatCurrency(deal.value)}
                        </span>

                        {deal.priority === 'HIGH' && (
                             <AlertCircle className="w-4 h-4 text-red-500" title="Alta Prioridade" />
                        )}
                    </div>

                    <div className="mt-3 pt-2 border-t border-gray-50 flex items-center justify-between text-[10px] text-gray-400">
                        <span className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" /> {new Date(deal.createdAt).toLocaleDateString()}
                        </span>
                        <div className="w-5 h-5 rounded-full bg-nexus-royal text-white flex items-center justify-center font-bold text-[8px]">
                            {deal.companyName.charAt(0)}
                        </div>
                    </div>
                  </div>
                ))}

                {/* Empty State / Drop Target Hint */}
                {stageDeals.length === 0 && (
                    <div className="h-24 border-2 border-dashed border-gray-200 rounded-lg flex items-center justify-center text-gray-400 text-xs italic">
                        Arraste negócios aqui
                    </div>
                )}
              </div>

              {/* Add Button */}
              <div className="p-2 pt-0 shrink-0">
                  <button 
                    onClick={() => onAddDeal(stage.id)}
                    className="w-full py-2 flex items-center justify-center gap-1 text-xs font-bold text-gray-500 hover:text-nexus-royal hover:bg-white rounded transition-colors"
                  >
                      <Plus className="w-3.5 h-3.5" /> Novo Negócio
                  </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PipelineBoard;

import React, { useState } from 'react';
import { Company } from '../types';
import { Phone, Globe, MapPin, Clock, Copy, MoreHorizontal, Check, Plus, MessageCircle, Map, Kanban } from 'lucide-react';
import { translations, Language } from '../utils/i18n';

interface LeadCardProps {
  company: Company;
  lang: Language;
  onSaveClick: (company: Company) => void;
  onAddToPipeline?: (company: Company) => void;
  isSaved?: boolean;
}

const LeadCard: React.FC<LeadCardProps> = ({ company, lang, onSaveClick, onAddToPipeline, isSaved = false }) => {
  const t = translations[lang];
  const [copied, setCopied] = useState(false);

  const copyCnpj = (e: React.MouseEvent) => {
    e.stopPropagation();
    if(company.cnpj === "Consultar" || company.cnpj === "Não Disponível") return;
    navigator.clipboard.writeText(company.cnpj);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const openWebsite = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (!company.website) return;
      let url = company.website;
      if (!url.startsWith('http://') && !url.startsWith('https://')) {
          url = 'https://' + url;
      }
      window.open(url, '_blank');
  };

  const openGoogleMaps = (e: React.MouseEvent) => {
      e.stopPropagation();
      const query = encodeURIComponent(`${company.nome_fantasia} ${company.endereco || company.cidade}`);
      window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  const openWhatsApp = (e: React.MouseEvent, phone: string) => {
      e.stopPropagation();
      const cleanPhone = phone.replace(/\D/g, '');
      let finalPhone = cleanPhone;
      // Basic logic to ensure BR country code if missing
      if (finalPhone.length >= 10 && finalPhone.length <= 11) {
          finalPhone = '55' + finalPhone;
      }
      // Use whatsapp:// protocol to force Desktop App
      window.open(`whatsapp://send?phone=${finalPhone}`, '_blank');
  };

  const normalize = (s: string) => s ? s.toLowerCase().trim() : '';
  const showLegalName = normalize(company.razão_social) !== normalize(company.nome_fantasia);

  return (
    <div className="group bg-white rounded border border-gray-200 shadow-sm hover:shadow-md transition-all duration-200 flex flex-col h-full overflow-hidden relative">

      {/* Top Border Indicator (HubSpot Style) */}
      <div className="absolute top-0 left-0 right-0 h-1 bg-gray-100 group-hover:bg-nexus-royal transition-colors"></div>

      {/* Header */}
      <div className="p-5 pb-3 flex justify-between items-start">
        <div className="flex-1 pr-4">
            <div className="flex items-center gap-2 mb-1">
                <h3 className="text-base font-bold text-nexus-dark hover:text-nexus-royal cursor-pointer line-clamp-1" title={company.nome_fantasia}>
                    {company.nome_fantasia}
                </h3>
                {company.is_open_now && (
                    <span className="w-2 h-2 rounded-full bg-emerald-500" title={t.status_open}></span>
                )}
            </div>
            {showLegalName && (
                <p className="text-xs text-gray-500 line-clamp-1" title={company.razão_social}>
                    {company.razão_social}
                </p>
            )}
        </div>
        <button className="text-gray-400 hover:text-nexus-dark p-1 rounded hover:bg-gray-100 transition-colors">
            <MoreHorizontal className="w-5 h-5" />
        </button>
      </div>

      {/* Properties Grid */}
      <div className="px-5 py-2 flex-grow space-y-3">

        {/* Source Badge */}
        <div className="flex items-center gap-2">
            <span className={`text-[10px] px-2 py-0.5 rounded font-bold uppercase tracking-wide border ${
                company.source === 'GOOGLE_MAPS' ? 'bg-blue-50 text-blue-700 border-blue-100' :
                company.source === 'GOV_DATA' ? 'bg-orange-50 text-orange-700 border-orange-100' :
                'bg-gray-50 text-gray-600 border-gray-100'
            }`}>
                {company.source.replace(/_/g, ' ')}
            </span>
        </div>

        <div className="h-px bg-gray-100 my-2"></div>

        {/* Data Rows */}
        <div className="space-y-2.5">
            {/* Location */}
            <div className="flex items-start gap-3">
                <MapPin className="w-4 h-4 text-gray-400 mt-0.5 shrink-0" />
                <div className="flex flex-col">
                    <span 
                        className="text-xs font-medium text-gray-700 line-clamp-2" 
                        title={company.endereco}
                    >
                        {company.endereco || company.cidade}
                    </span>
                    {!company.endereco && company.bairro && <span className="text-[10px] text-gray-500">{company.bairro}</span>}
                </div>
            </div>

            {/* Phone & WhatsApp */}
             <div className="flex items-center gap-3">
                <Phone className="w-4 h-4 text-gray-400 shrink-0" />
                <span className="text-xs font-medium text-gray-700 select-all truncate">
                    {company.telefone || <span className="text-gray-400 italic">--</span>}
                </span>
                {company.telefone && (
                    <button 
                        onClick={(e) => openWhatsApp(e, company.telefone!)}
                        className="p-1 text-green-600 hover:bg-green-50 rounded-full transition-colors ml-auto flex items-center gap-1 text-[10px] font-bold border border-transparent hover:border-green-200"
                        title="Conversar no WhatsApp"
                    >
                        <MessageCircle className="w-3.5 h-3.5" />
                        <span className="hidden group-hover:inline">WhatsApp</span>
                    </button>
                )}
            </div>

            {/* Website */}
            <div className="flex items-center gap-3">
                <Globe className="w-4 h-4 text-gray-400 shrink-0" />
                {company.website ? (
                    <span 
                        onClick={openWebsite} 
                        className="text-xs font-medium text-nexus-royal hover:underline cursor-pointer truncate max-w-[180px]"
                    >
                        {company.website}
                    </span>
                ) : (
                    <span className="text-xs text-gray-400 italic">--</span>
                )}
            </div>

            {/* Hours */}
            <div className="flex items-center gap-3">
                <Clock className="w-4 h-4 text-gray-400 shrink-0" />
                <span className="text-xs text-gray-600 truncate">
                    {company.opening_hours || <span className="text-gray-400 italic">{t.hours_unavailable}</span>}
                </span>
            </div>
        </div>
      </div>

      {/* Footer Actions */}
      <div className="px-5 py-4 mt-2 border-t border-gray-100 bg-gray-50/50 flex items-center justify-between">

          <div className="flex items-center gap-3">
             {/* CNPJ Copy */}
             <div 
                className="flex items-center gap-1.5 cursor-pointer group/copy"
                onClick={copyCnpj}
                title="Copiar CNPJ"
             >
                <span className="text-[10px] font-mono text-gray-400 group-hover/copy:text-gray-600 transition-colors">
                    {company.cnpj}
                </span>
                {copied ? <Check className="w-3 h-3 text-emerald-500" /> : <Copy className="w-3 h-3 text-gray-300 group-hover/copy:text-gray-500" />}
             </div>

             {/* Google Maps External Link */}
             <button 
                onClick={openGoogleMaps}
                title="Ver no Google Maps"
                className="text-gray-400 hover:text-nexus-royal transition-colors"
             >
                 <Map className="w-3.5 h-3.5" />
             </button>
          </div>

          <div className="flex items-center gap-2">
             {/* Create Deal Button */}
             {onAddToPipeline && (
                <button 
                  onClick={(e) => { e.stopPropagation(); onAddToPipeline(company); }}
                  className="p-1.5 bg-white border border-gray-200 text-gray-500 hover:text-nexus-royal hover:border-nexus-royal rounded shadow-sm transition-all"
                  title="Criar Negócio no Pipeline"
                >
                    <Kanban className="w-3.5 h-3.5" />
                </button>
             )}

            {/* Save List Button */}
            <button 
                onClick={(e) => { e.preventDefault(); e.stopPropagation(); onSaveClick(company); }}
                className={`flex items-center gap-1.5 text-xs font-bold px-3 py-1.5 rounded transition-all border shadow-sm ${
                    isSaved 
                    ? 'bg-emerald-50 text-emerald-700 border-emerald-200 hover:bg-emerald-100' 
                    : 'bg-white text-nexus-royal border-gray-200 hover:border-nexus-royal hover:bg-blue-50'
                }`}>
                {isSaved ? (
                    <>
                    <Check className="w-3.5 h-3.5" /> {t.actions_saved}
                    </>
                ) : (
                    <>
                    <Plus className="w-3.5 h-3.5" /> {t.actions_save}
                    </>
                )}
            </button>
          </div>
      </div>
    </div>
  );
};

export default LeadCard;

