                        </div>
                    ) : (
                        <div>
                            <LeadListView 
                                leads={currentLeads} 
                                lang={currentLang} 
                                onSaveLead={handleSaveSingleLead}
                                onAddToPipeline={handleOpenAddToPipeline} 
                            />
                        </div>
                    )}

                   {!activeListId && (
