      e.preventDefault();
      if (!newTaskInput.trim()) return;
      const newTask: Task = {
          id: Date.now().toString(),
          text: newTaskInput,
          completed: false
      };
      setTasks([...tasks, newTask]);
      setNewTaskInput('');
      setShowTaskInput(false);
