                                          <div className="w-10 h-10 rounded-full bg-nexus-royal/10 text-nexus-royal flex items-center justify-center font-bold text-sm">
                                              {p.name.charAt(0)}
                                          </div>
                                          <div>
                                              <div className="text-sm font-bold text-gray-900">{p.name}</div>
