export default DealDetailsModal;

import React, { useState } from 'react';
import { Pipeline, Deal } from '../types';
import { Plus, MoreHorizontal, DollarSign, Calendar, AlertCircle } from 'lucide-react';
import { formatCurrency } from '../utils/estimation';

interface PipelineBoardProps {
  pipeline: Pipeline;
  deals: Deal[];
  onDealMove: (dealId: string, newStageId: string) => void;
  onDealClick: (deal: Deal) => void;
  onAddDeal: (stageId: string) => void;
}

const PipelineBoard: React.FC<PipelineBoardProps> = ({ 
  pipeline, 
  deals, 
  onDealMove,
  onDealClick,
  onAddDeal
}) => {
  const [draggedDealId, setDraggedDealId] = useState<string | null>(null);
  const [dragOverStageId, setDragOverStageId] = useState<string | null>(null);

  const handleDragStart = (e: React.DragEvent, dealId: string) => {
    setDraggedDealId(dealId);
    e.dataTransfer.effectAllowed = 'move';
    // Transparent ghost image or custom logic could go here
  };

  const handleDragOver = (e: React.DragEvent, stageId: string) => {
    e.preventDefault(); // Necessary to allow dropping
    if (dragOverStageId !== stageId) {
        setDragOverStageId(stageId);
    }
  };

  const handleDragLeave = () => {
    setDragOverStageId(null);
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    setDragOverStageId(null);
    if (draggedDealId) {
      onDealMove(draggedDealId, stageId);
      setDraggedDealId(null);
    }
  };

  // Calculate totals per stage
  const getStageSummary = (stageId: string) => {
      const stageDeals = deals.filter(d => d.stageId === stageId && d.pipelineId === pipeline.id);
      const totalValue = stageDeals.reduce((sum, d) => sum + (d.value || 0), 0);
      return { count: stageDeals.length, value: totalValue };
  };

  return (
    <div className="h-full overflow-x-auto overflow-y-hidden pb-4">
      <div className="flex h-full gap-4 min-w-max px-1">
        {pipeline.stages.map((stage) => {
          const stageDeals = deals.filter(deal => deal.stageId === stage.id && deal.pipelineId === pipeline.id);
          const summary = getStageSummary(stage.id);
          const isOver = dragOverStageId === stage.id;

          return (
            <div 
              key={stage.id}
              className={`flex flex-col w-80 max-w-xs rounded-xl transition-colors duration-200 ${isOver ? 'bg-blue-50/80 ring-2 ring-nexus-royal/20' : 'bg-gray-100/50'}`}
              onDragOver={(e) => handleDragOver(e, stage.id)}
              onDragLeave={handleDragLeave}
              onDrop={(e) => handleDrop(e, stage.id)}
            >
              {/* Column Header */}
              <div className="p-3 border-b border-gray-200/50 shrink-0 bg-white/40 rounded-t-xl backdrop-blur-sm">
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                     <span className="font-bold text-sm text-nexus-dark uppercase tracking-tight">{stage.name}</span>
                     <span className="bg-gray-200 text-gray-600 px-1.5 py-0.5 rounded text-[10px] font-bold">{summary.count}</span>
                  </div>
                  <MoreHorizontal className="w-4 h-4 text-gray-400 cursor-pointer hover:text-nexus-dark" />
                </div>
                <div className="h-1 w-full rounded-full bg-gray-200 overflow-hidden mb-2">
                    <div className="h-full rounded-full" style={{ width: '100%', backgroundColor: stage.color }}></div>
                </div>
                <div className="text-xs text-gray-500 font-medium">
                   {formatCurrency(summary.value)}
                </div>
              </div>

              {/* Deals Container */}
              <div className="flex-1 overflow-y-auto p-2 space-y-2 custom-scrollbar">
                {stageDeals.map((deal) => (
                  <div
                    key={deal.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, deal.id)}
                    onClick={() => onDealClick(deal)}
                    className={`bg-white p-3 rounded-lg border shadow-sm cursor-grab active:cursor-grabbing hover:shadow-md transition-all group relative border-l-4 ${draggedDealId === deal.id ? 'opacity-50 rotate-3 scale-95' : 'opacity-100'}`}
                    style={{ borderLeftColor: stage.color }}
                  >
                    <div className="flex justify-between items-start mb-2">
                        <span className="text-sm font-bold text-gray-800 line-clamp-2 leading-tight">
                            {deal.companyName}
                        </span>
                    </div>

                    <div className="flex items-center justify-between mt-3">
                        <span className="text-xs font-bold text-gray-600 bg-gray-50 px-2 py-1 rounded border border-gray-100">
                           {formatCurrency(deal.value)}
                        </span>

                        {deal.priority === 'HIGH' && (
                             <AlertCircle className="w-4 h-4 text-red-500" title="Alta Prioridade" />
                        )}
                    </div>

                    <div className="mt-3 pt-2 border-t border-gray-50 flex items-center justify-between text-[10px] text-gray-400">
                        <span className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" /> {new Date(deal.createdAt).toLocaleDateString('pt-BR')}
                        </span>
                        <div className="w-5 h-5 rounded-full bg-nexus-royal text-white flex items-center justify-center font-bold text-[8px]">
                            {deal.companyName.charAt(0)}
                        </div>
                    </div>
                  </div>
                ))}

                {/* Empty State / Drop Target Hint */}
                {stageDeals.length === 0 && (
                    <div className="h-24 border-2 border-dashed border-gray-200 rounded-lg flex items-center justify-center text-gray-400 text-xs italic">
                        Arraste negócios aqui
                    </div>
                )}
              </div>

              {/* Add Button */}
              <div className="p-2 pt-0 shrink-0">
                  <button 
                    onClick={() => onAddDeal(stage.id)}
                    className="w-full py-2 flex items-center justify-center gap-1 text-xs font-bold text-gray-500 hover:text-nexus-royal hover:bg-white rounded transition-colors"
                  >
                      <Plus className="w-3.5 h-3.5" /> Novo Negócio
                  </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PipelineBoard;

import React, { useState } from 'react';
import { X, LayoutTemplate, CheckSquare, Square, GitBranch, Plus, Trash2, Edit2, ChevronRight, GripVertical, Palette, Check } from 'lucide-react';
import { CardVisibilityConfig, Pipeline, PipelineStage } from '../types';
import { STAGE_COLORS } from '../constants';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  cardConfig: CardVisibilityConfig;
  onUpdateCardConfig: (key: keyof CardVisibilityConfig) => void;
  pipelines: Pipeline[];
  setPipelines: (pipelines: Pipeline[]) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ 
  isOpen, 
  onClose, 
  cardConfig, 
  onUpdateCardConfig,
  pipelines,
  setPipelines
}) => {
  const [activeTab, setActiveTab] = useState<'view' | 'stages'>('stages');
  const [expandedColorPicker, setExpandedColorPicker] = useState<string | null>(null);

  if (!isOpen) return null;

  // Since we only have one pipeline now, we always edit the first one
  const activePipeline = pipelines[0];

  const updatePipelineName = (name: string) => {
      const updated = pipelines.map(p => p.id === activePipeline.id ? { ...p, name } : p);
      setPipelines(updated);
  };

  const updateStage = (stageId: string, updates: Partial<PipelineStage>) => {
      const newStages = activePipeline.stages.map(s => s.id === stageId ? { ...s, ...updates } : s);
      const updated = pipelines.map(p => p.id === activePipeline.id ? { ...p, stages: newStages } : p);
      setPipelines(updated);
  };

  const addStage = () => {
      const newStage: PipelineStage = {
          id: crypto.randomUUID(),
          name: 'Nova Etapa',
          color: STAGE_COLORS[0]
      };
      const updated = pipelines.map(p => 
          p.id === activePipeline.id ? { ...p, stages: [...p.stages, newStage] } : p
      );
      setPipelines(updated);
  };

  const removeStage = (stageId: string) => {
       if (activePipeline.stages.length <= 1) return;
       const updated = pipelines.map(p => 
          p.id === activePipeline.id ? { ...p, stages: p.stages.filter(s => s.id !== stageId) } : p
      );
      setPipelines(updated);
  };

  // --- Render Helpers ---

  const OptionRow = ({ label, configKey }: { label: string, configKey: keyof CardVisibilityConfig }) => (
      <div 
        onClick={() => onUpdateCardConfig(configKey)}
        className="flex items-center justify-between p-3 rounded border border-gray-100 hover:bg-blue-50 cursor-pointer transition-colors group"
      >
          <span className="text-sm font-medium text-gray-700">{label}</span>
          {cardConfig[configKey] ? (
              <CheckSquare className="w-5 h-5 text-nexus-royal" />
          ) : (
              <Square className="w-5 h-5 text-gray-300 group-hover:text-gray-400" />
          )}
      </div>
  );

  return (
    <div className="fixed inset-0 z-[1400] flex items-center justify-center bg-nexus-sidebar/80 backdrop-blur-sm animate-fadeIn p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col h-[85vh]">

        {/* Header */}
        <div className="p-5 border-b border-gray-200 flex justify-between items-center bg-gray-50 shrink-0">
            <h2 className="text-lg font-bold text-nexus-dark flex items-center gap-2">
                Configurações do Funil
            </h2>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
                <X className="w-5 h-5" />
            </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-200 px-6 shrink-0 bg-white">
            <button 
                onClick={() => setActiveTab('stages')}
                className={`py-3 px-4 text-sm font-bold border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'stages' ? 'border-nexus-royal text-nexus-royal' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
                <GitBranch className="w-4 h-4" /> Etapas do Funil
            </button>
            <button 
                onClick={() => setActiveTab('view')}
                className={`py-3 px-4 text-sm font-bold border-b-2 transition-colors ${activeTab === 'view' ? 'border-nexus-royal text-nexus-royal' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
                Visualização do Cartão
            </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-hidden bg-gray-50/50">

            {/* STAGES CONFIG TAB */}
            {activeTab === 'stages' && (
                <div className="flex-1 overflow-y-auto p-8 h-full">
                    <div className="max-w-2xl mx-auto">
                        <div className="bg-white p-6 rounded-lg border border-gray-200 shadow-sm mb-6">
                            <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Nome do Funil</label>
                            <input 
                                type="text" 
                                value={activePipeline.name}
                                onChange={(e) => updatePipelineName(e.target.value)}
                                className="w-full text-lg font-bold text-nexus-dark border-b border-gray-300 focus:border-nexus-royal outline-none py-1 bg-transparent placeholder-gray-300"
                                placeholder="Ex: Funil de Vendas Padrão"
                            />
                        </div>

                        <div className="mb-4 flex items-center justify-between">
                            <h3 className="text-sm font-bold text-gray-700 flex items-center gap-2">
                                <GitBranch className="w-4 h-4 text-nexus-royal" />
                                Etapas ({activePipeline.stages.length})
                            </h3>
                            <button 
                                onClick={addStage}
                                className="text-xs font-bold text-nexus-royal bg-white border border-nexus-royal/20 px-3 py-1.5 rounded hover:bg-blue-50 flex items-center gap-1 shadow-sm transition-all"
                            >
                                <Plus className="w-3 h-3" /> Adicionar Etapa
                            </button>
                        </div>

                        <div className="space-y-3">
                            {activePipeline.stages.map((stage, index) => (
                                <div key={stage.id} className="bg-white p-4 rounded border border-gray-200 shadow-sm group transition-all hover:border-nexus-royal/30">
                                    <div className="flex items-center gap-4">
                                        <div className="text-gray-300 cursor-grab hover:text-gray-500">
                                            <GripVertical className="w-4 h-4" />
                                        </div>

                                        {/* Color Picker - INLINE */}
                                        <div className="relative">
                                            <button 
                                                onClick={() => setExpandedColorPicker(expandedColorPicker === stage.id ? null : stage.id)}
                                                className="w-6 h-6 rounded-full border border-gray-200 shadow-sm transition-transform hover:scale-110 focus:ring-2 focus:ring-offset-2 focus:ring-nexus-royal"
                                                style={{ backgroundColor: stage.color }}
                                                title="Mudar Cor"
                                            ></button>
                                        </div>

                                        <div className="flex-1">
                                             <input 
                                                type="text" 
                                                value={stage.name}
                                                onChange={(e) => updateStage(stage.id, { name: e.target.value })}
                                                className="w-full text-sm font-bold text-gray-700 outline-none border-b border-transparent focus:border-nexus-royal bg-transparent transition-colors"
                                                placeholder="Nome da etapa"
                                            />
                                        </div>

                                        <button 
                                            onClick={() => removeStage(stage.id)}
                                            className="text-gray-300 hover:text-red-500 transition-colors p-2 hover:bg-red-50 rounded"
                                            title="Remover Etapa"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>

                                    {/* Inline Color Palette */}
                                    {expandedColorPicker === stage.id && (
                                        <div className="mt-3 pt-3 border-t border-gray-100 animate-fadeIn flex items-center gap-2 overflow-x-auto pb-1">
                                            <span className="text-[10px] text-gray-400 font-bold uppercase mr-2">Cor:</span>
                                            {STAGE_COLORS.map(c => (
                                                <button 
                                                    key={c}
                                                    onClick={() => { updateStage(stage.id, { color: c }); setExpandedColorPicker(null); }}
                                                    className={`w-6 h-6 rounded-full border transition-all flex items-center justify-center shrink-0 ${stage.color === c ? 'border-gray-400 scale-110 ring-1 ring-gray-300' : 'border-gray-100 hover:scale-110'}`}
                                                    style={{ backgroundColor: c }}
                                                >
                                                    {stage.color === c && <Check className="w-3 h-3 text-gray-600/50" />}
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {/* VIEW CONFIG TAB */}
            {activeTab === 'view' && (
                <div className="p-8 h-full overflow-y-auto">
                    <div className="max-w-lg mx-auto">
                        <div className="mb-6">
                            <h3 className="text-xs font-bold text-nexus-slate uppercase tracking-wider mb-3 flex items-center gap-2">
                                <LayoutTemplate className="w-4 h-4" /> Personalizar Cartões
                            </h3>
                            <p className="text-xs text-gray-500 mb-6 leading-relaxed">
                                Escolha quais informações aparecem nos cartões do Pipeline para otimizar a visualização e focar no que importa.
                            </p>

                            <div className="space-y-2 bg-white p-4 rounded-lg border border-gray-200 shadow-sm">
                                <OptionRow label="ID do Negócio" configKey="showId" />
                                <OptionRow label="Valor Estimado" configKey="showValue" />
                                <OptionRow label="Prioridade" configKey="showPriority" />
                                <OptionRow label="Data de Criação" configKey="showDate" />
                                <OptionRow label="Telefone e Website" configKey="showContactInfo" />
                                <OptionRow label="Localização" configKey="showLocation" />
                                <OptionRow label="Tags / Campos Personalizados" configKey="showTags" />
                            </div>
                        </div>
                    </div>
                </div>
            )}

        </div>

        <div className="p-4 border-t border-gray-200 bg-gray-50 flex justify-end shrink-0">
            <button 
                onClick={onClose}
                className="px-6 py-2.5 bg-nexus-royal text-white text-sm font-bold rounded shadow-sm hover:bg-blue-700 transition-colors"
            >
                Concluir
            </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState, useEffect } from 'react';
import { Deal, Pipeline, ActivityLog, LeadPerson, DealTask } from '../types';
import { translations, Language } from '../utils/i18n';
import { 
  X, Building2, MapPin, Phone, Trash2, Plus, 
  ChevronRight, ChevronDown, Mail, Link as LinkIcon, Briefcase, 
  CheckCircle2, Settings, FileText, CheckSquare,
  Users, Activity, Database, LayoutGrid,
  MessageSquare, AlertCircle, MessageCircle, Mic
} from 'lucide-react';

interface DealDetailsModalProps {
  isOpen: boolean;
  onClose: () => void;
  deal: Deal | null;
  onSave: (updatedDeal: Deal) => void;
  onDelete: (dealId: string) => void;
  lang: Language;
  pipelines: Pipeline[];
}

const DealDetailsModal: React.FC<DealDetailsModalProps> = ({ 
  isOpen, 
  onClose, 
  deal, 
  onSave, 
  onDelete, 
  lang,
  pipelines 
}) => {
  const t = translations[lang];
  const [formData, setFormData] = useState<Deal | null>(null);

  // Navigation State
  const [activeTab, setActiveTab] = useState('Visão Geral');
  const [insightTab, setInsightTab] = useState('Pontuação');

  // Sidebar State
  const [expandedSections, setExpandedSections] = useState({
    companyDetails: true,
    recordDetails: true,
    tasks: true,
    deals: true
  });

  // Local Task Input State (Actual tasks are in formData.tasks)
  const [newTaskInput, setNewTaskInput] = useState('');
  const [showTaskInput, setShowTaskInput] = useState(false);

  // Activity State
  const [newActivityContent, setNewActivityContent] = useState('');
  const [activityType, setActivityType] = useState<'CALL' | 'EMAIL' | 'MEETING' | 'NOTE'>('NOTE');

  // People State
  const [isAddingPerson, setIsAddingPerson] = useState(false);
  const [newPersonName, setNewPersonName] = useState('');
  const [newPersonTitle, setNewPersonTitle] = useState('');

  useEffect(() => {
    if (deal) {
      setFormData({ ...deal });
      // If deal doesn't have arrays initialized (legacy data), init them
      if (!deal.activities) setFormData(prev => prev ? ({...prev, activities: []}) : null);
      if (!deal.people) setFormData(prev => prev ? ({...prev, people: []}) : null);
      if (!deal.tasks) setFormData(prev => prev ? ({...prev, tasks: []}) : null);
    }
  }, [deal]);

  if (!isOpen || !formData) return null;

  const toggleSection = (key: keyof typeof expandedSections) => {
    setExpandedSections(prev => ({...prev, [key]: !prev[key]}));
  };

  const handleAddTask = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskInput.trim()) return;
      const newTask: DealTask = {
          id: Date.now().toString(),
          text: newTaskInput,
          completed: false,
          createdAt: new Date().toISOString()
      };

      const updatedTasks = [...(formData.tasks || []), newTask];
      setFormData({ ...formData, tasks: updatedTasks });
      setNewTaskInput('');
      setShowTaskInput(false);
  };

  const toggleTask = (taskId: string) => {
      const updatedTasks = (formData.tasks || []).map(t => 
          t.id === taskId ? { ...t, completed: !t.completed } : t
      );
      setFormData({ ...formData, tasks: updatedTasks });
  };

  const handleLogActivity = () => {
      if (!newActivityContent.trim()) return;

      const newActivity: ActivityLog = {
          id: Date.now().toString(),
          type: activityType,
          content: newActivityContent,
          createdAt: new Date().toISOString(),
          user: 'Você' // Placeholder for current user
      };

      const updatedActivities = [newActivity, ...(formData.activities || [])];
      setFormData({ ...formData, activities: updatedActivities });
      setNewActivityContent('');
  };

  const handleAddPerson = () => {
      if (!newPersonName.trim()) return;

      const newPerson: LeadPerson = {
          id: Date.now().toString(),
          name: newPersonName,
          title: newPersonTitle,
          location: formData.contactInfo?.location || 'Desconhecido',
          department: 'Geral',
          emailRevealed: false
      };

      const updatedPeople = [...(formData.people || []), newPerson];
      setFormData({ ...formData, people: updatedPeople });
      setIsAddingPerson(false);
      setNewPersonName('');
      setNewPersonTitle('');
  };

  const removePerson = (personId: string) => {
      const updatedPeople = (formData.people || []).filter(p => p.id !== personId);
      setFormData({ ...formData, people: updatedPeople });
  };

  const revealEmail = (personId: string) => {
      const updatedPeople = (formData.people || []).map(p => {
          if (p.id === personId) {
             // Mock deterministic email based on name
             const cleanName = p.name.split(' ')[0].toLowerCase().replace(/[^a-z]/g, '');
             const cleanCompany = formData.companyName.toLowerCase().replace(/[^a-z0-9]/g, '');
             const mockEmail = `${cleanName}@${cleanCompany}.com.br`;
             return { ...p, emailRevealed: true, email: mockEmail };
          }
          return p;
      });
      setFormData({ ...formData, people: updatedPeople });
  };

  const openWhatsApp = (phone: string | undefined) => {
      if (!phone) return;
      const cleanPhone = phone.replace(/\D/g, '');
      let finalPhone = cleanPhone;
      if (finalPhone.length >= 10 && finalPhone.length <= 11) {
          finalPhone = '55' + finalPhone;
      }
      window.open(`whatsapp://send?phone=${finalPhone}`, '_blank');
  };

  const getActivityIcon = (type: string) => {
      switch(type) {
          case 'CALL': return <Phone className="w-4 h-4 text-purple-600" />;
          case 'EMAIL': return <Mail className="w-4 h-4 text-blue-600" />;
          case 'MEETING': return <Users className="w-4 h-4 text-orange-600" />;
          case 'NOTE': return <FileText className="w-4 h-4 text-yellow-600" />;
          default: return <Activity className="w-4 h-4 text-gray-600" />;
      }
  };

  // Dynamic Score Calculation
  const calculateScore = () => {
      let score = 0;
      if (formData.companyName) score += 10;
      if (formData.contactInfo?.phone) score += 20;
      if (formData.contactInfo?.website) score += 20;
      if (formData.contactInfo?.location) score += 10;
      if (formData.activities && formData.activities.length > 0) score += 20;
      if (formData.people && formData.people.length > 0) score += 20;
      return Math.min(score, 100);
  };
  const engagementScore = calculateScore();

  // --- RENDER HELPERS ---

  const renderTabContent = () => {
      switch (activeTab) {
          case 'Visão Geral':
              return (
                <div className="space-y-6">
                    {/* Insights Card */}
                    <div className="bg-white rounded border border-gray-200 shadow-sm animate-fadeIn">
                        <div className="flex items-center justify-between p-4 pb-0">
                            <div className="flex items-center gap-2">
                                <LayoutGrid className="w-4 h-4 text-gray-500" />
                                <span className="text-sm font-bold text-gray-800">Insights da Empresa</span>
                            </div>
                            <div className="flex gap-2">
                                <Settings className="w-4 h-4 text-gray-400 cursor-pointer hover:text-gray-600" />
                            </div>
                        </div>

                        {/* Subtabs */}
                        <div className="px-4 border-b border-gray-100 flex gap-6 mt-3 overflow-x-auto no-scrollbar">
                             {['Pontuação', 'Notícias', 'Tecnologias', 'Tendências', 'Visitantes'].map(t => (
                                 <span 
                                    key={t} 
                                    onClick={() => setInsightTab(t)} 
                                    className={`text-xs font-medium pb-2 cursor-pointer border-b-2 transition-colors whitespace-nowrap ${insightTab === t ? 'text-gray-900 border-gray-900' : 'text-gray-500 border-transparent hover:text-gray-700'}`}
                                 >
                                     {t}
                                 </span>
                             ))}
                        </div>

                        <div className="p-6 bg-white min-h-[120px]">
                             {insightTab === 'Pontuação' && (
                                <div className="flex items-start gap-4 animate-fadeIn">
                                    <div className="p-3 bg-purple-50 rounded-lg border border-purple-100">
                                        <div className="w-8 h-8 flex items-center justify-center bg-white rounded-md shadow-sm border border-purple-100">
                                            <div 
                                                className="w-4 h-2 bg-purple-300 rounded-full transition-all duration-500"
                                                style={{ width: `${engagementScore / 6}px` }} 
                                            ></div>
                                        </div>
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-sm text-gray-900">Score de Engajamento: {engagementScore}/100</h4>
                                        <p className="text-xs text-gray-500 mt-1 mb-3 leading-relaxed">Calculado com base no preenchimento do perfil, contatos e atividades recentes.</p>
                                    </div>
                                </div>
                             )}
                             {insightTab === 'Tecnologias' && (
                                 <div className="animate-fadeIn">
                                     <h4 className="font-bold text-sm text-gray-900 mb-2">Stack Tecnológica Detectada</h4>
                                     <div className="flex flex-wrap gap-2">
                                         {['Google Analytics', 'WordPress', 'jQuery'].map(tech => (
                                             <span key={tech} className="px-2 py-1 bg-blue-50 text-blue-700 text-xs font-bold rounded border border-blue-100">{tech}</span>
                                         ))}
                                     </div>
                                     <p className="text-[10px] text-gray-400 mt-2 italic">* Dados simulados baseados no segmento.</p>
                                 </div>
                             )}
                             {insightTab === 'Notícias' && (
                                 <div className="animate-fadeIn text-sm text-gray-600">
                                     <p>Nenhuma notícia recente encontrada para <strong>{formData.companyName}</strong> nos últimos 30 dias.</p>
                                 </div>
                             )}
                             {!['Pontuação', 'Tecnologias', 'Notícias'].includes(insightTab) && (
                                 <div className="flex flex-col items-center justify-center py-4 text-gray-400 animate-fadeIn">
                                     <AlertCircle className="w-8 h-8 mb-2 opacity-50" />
                                     <span className="text-xs">Dados indisponíveis para {insightTab} no momento.</span>
                                 </div>
                             )}
                        </div>
                    </div>
                </div>
              );
          case 'Atividades':
              return (
                  <div className="space-y-6 animate-fadeIn">
                      {/* Activity Composer */}
                      <div className="bg-white rounded border border-gray-200 shadow-sm overflow-hidden">
                          <div className="flex border-b border-gray-100 bg-gray-50">
                              <button 
                                onClick={() => setActivityType('NOTE')}
                                className={`flex-1 py-3 text-xs font-bold flex items-center justify-center gap-2 ${activityType === 'NOTE' ? 'bg-white text-gray-900 border-t-2 border-t-nexus-royal' : 'text-gray-500 hover:bg-gray-100'}`}
                              >
                                  <FileText className="w-4 h-4" /> Nota
                              </button>
                              <button 
                                onClick={() => setActivityType('CALL')}
                                className={`flex-1 py-3 text-xs font-bold flex items-center justify-center gap-2 ${activityType === 'CALL' ? 'bg-white text-gray-900 border-t-2 border-t-nexus-royal' : 'text-gray-500 hover:bg-gray-100'}`}
                              >
                                  <Phone className="w-4 h-4" /> Ligação
                              </button>
                              <button 
                                onClick={() => setActivityType('EMAIL')}
                                className={`flex-1 py-3 text-xs font-bold flex items-center justify-center gap-2 ${activityType === 'EMAIL' ? 'bg-white text-gray-900 border-t-2 border-t-nexus-royal' : 'text-gray-500 hover:bg-gray-100'}`}
                              >
                                  <Mail className="w-4 h-4" /> Email
                              </button>
                              <button 
                                onClick={() => setActivityType('MEETING')}
                                className={`flex-1 py-3 text-xs font-bold flex items-center justify-center gap-2 ${activityType === 'MEETING' ? 'bg-white text-gray-900 border-t-2 border-t-nexus-royal' : 'text-gray-500 hover:bg-gray-100'}`}
                              >
                                  <Users className="w-4 h-4" /> Reunião
                              </button>
                          </div>
                          <div className="p-4">
                              <textarea 
                                  className="w-full text-sm border border-gray-200 rounded p-3 focus:ring-1 focus:ring-nexus-royal outline-none min-h-[100px] resize-y mb-3"
                                  placeholder={`Descreva a ${activityType === 'CALL' ? 'ligação' : activityType === 'NOTE' ? 'nota' : activityType === 'EMAIL' ? 'mensagem' : 'reunião'}...`}
                                  value={newActivityContent}
                                  onChange={(e) => setNewActivityContent(e.target.value)}
                              />
                              <div className="flex justify-between items-center">
                                  <div className="flex gap-2 text-gray-400">
                                      <Mic className="w-4 h-4 cursor-pointer hover:text-gray-600" />
                                      <LinkIcon className="w-4 h-4 cursor-pointer hover:text-gray-600" />
                                  </div>
                                  <button 
                                    onClick={handleLogActivity}
                                    disabled={!newActivityContent.trim()}
                                    className="bg-nexus-royal text-white px-4 py-2 rounded text-xs font-bold hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
                                  >
                                      Registrar
                                  </button>
                              </div>
                          </div>
                      </div>

                      {/* Timeline */}
                      <div className="relative pl-4 space-y-6 before:absolute before:left-[19px] before:top-2 before:bottom-0 before:w-px before:bg-gray-200">
                          {(formData.activities || []).length === 0 ? (
                              <div className="text-center py-10 text-gray-400 italic text-sm bg-gray-50 rounded border border-dashed border-gray-200">
                                  Nenhuma atividade registrada. Comece adicionando uma nota.
                              </div>
                          ) : (
                              (formData.activities || []).map((activity, idx) => (
                                  <div key={activity.id || idx} className="relative pl-8">
                                      <div className={`absolute left-0 top-0 w-10 h-10 rounded-full border-2 border-white shadow-sm flex items-center justify-center bg-white z-10`}>
